from fastapi import APIRouter, Request, HTTPException, Header
from fastapi.responses import StreamingResponse
from typing import Optional, Dict, Any
import httpx
import json
from loguru import logger
from llmproxy.config import settings
import redis.asyncio as redis
router = APIRouter()

async def get_model_service_url(redis_client: redis.Redis, model: str) -> Optional[str]:
    """从 Redis 获取 model 对应的服务地址"""
    try:
        key = f"{settings.REDIS_MODEL_KEY_PREFIX}:{model}"
        logger.info(f"Getting service URL for model '{model}' from Redis with key: {key}")
        service_url = await redis_client.get(key)
        if service_url:
            logger.info(f"Found service URL for model '{model}': {service_url}")
            return service_url
        else:
            logger.error(f"No service URL found for model '{model}' in Redis")
            return None
    except Exception as exc:
        logger.error(f"Error getting model service URL from Redis: {exc}")
        return None

async def forward_request(
    url: str,
    method: str,
    headers: Dict[str, str],
    json_data: Optional[Dict[str, Any]] = None
):
    """转发请求到 LLM API"""
    async with httpx.AsyncClient(timeout=settings.PROXY_TIMEOUT) as client:
        try:
            if method.upper() == "POST":
                response = await client.post(
                    url,
                    headers=headers,
                    json=json_data,
                    follow_redirects=True
                )
            elif method.upper() == "GET":
                response = await client.get(
                    url,
                    headers=headers,
                    follow_redirects=True
                )
            else:
                raise HTTPException(status_code=405, detail=f"Method {method} not allowed")

            return response
        except httpx.TimeoutException as exc:
            logger.error(f"Request timeout: {url}")
            raise HTTPException(status_code=504, detail="Request timeout") from exc
        except httpx.RequestError as exc:
            logger.error(f"Request error: {exc}")
            raise HTTPException(status_code=502, detail=f"Request error: {str(exc)}") from exc

def build_llm_headers(request_headers: Dict[str, str]) -> Dict[str, str]:
    """构建转发到 LLM API 的请求头"""
    headers = {}

    # 复制必要的请求头
    for key in ["authorization", "content-type", "x-api-key"]:
        if key in request_headers:
            headers[key] = request_headers[key]

    # 如果没有 authorization，使用配置的 API key
    if "authorization" not in headers and settings.LLM_API_KEY:
        headers["authorization"] = f"Bearer {settings.LLM_API_KEY}"

    # 设置默认 content-type
    if "content-type" not in headers:
        headers["content-type"] = "application/json"

    return headers

@router.post("/chat/completions")
@router.post("/chat/completions/")
async def proxy_chat_completions(
    request: Request,
    authorization: Optional[str] = Header(None, alias="Authorization")
):
    """代理聊天补全请求，支持 SSE 流式响应，根据 model 从 Redis 获取服务地址"""
    try:
        # 获取请求体
        body = await request.json()
        stream = body.get("stream", False)
        model = body.get("model")

        # 从 Redis 获取 model 对应的服务地址
        redis_client = request.app.state.redis
        service_base_url = None

        if model:
            service_base_url = await get_model_service_url(redis_client, model)

        # 如果找到了服务地址，使用它；否则使用默认地址
        if service_base_url:
            # 确保 URL 格式正确（移除末尾的斜杠）
            service_base_url = service_base_url.rstrip("/")
            target_url = f"{service_base_url}/v1/chat/completions"
            logger.info(f"Routing model '{model}' to service: {target_url}")
        else:
            # 使用默认服务地址
            target_url = f"{settings.LLM_API_BASE_URL}/v1/chat/completions"
            if model:
                logger.warning(f"Model '{model}' not found in Redis, using default service: {target_url}")
            else:
                logger.info(f"No model specified, using default service: {target_url}")

        # 构建请求头
        request_headers = {}
        if authorization:
            request_headers["authorization"] = authorization

        headers = build_llm_headers(request_headers)

        logger.info(f"Proxying request to {target_url}, stream={stream}, model={model}")

        # 如果是流式请求，使用 SSE
        if stream:
            async def generate_sse():
                async with httpx.AsyncClient(timeout=settings.PROXY_TIMEOUT) as client:
                    try:
                        async with client.stream(
                            "POST",
                            target_url,
                            headers=headers,
                            json=body,
                            follow_redirects=True
                        ) as response:
                            if response.status_code != 200:
                                error_text = await response.aread()
                                logger.error(f"LLM API error: {response.status_code}, {error_text.decode()}")
                                yield f"data: {json.dumps({'error': {'message': error_text.decode(), 'code': response.status_code}})}\n\n"
                                return

                            async for chunk in response.aiter_bytes():
                                if chunk:
                                    # 直接转发 SSE 数据
                                    yield chunk.decode('utf-8', errors='ignore')
                    except httpx.RequestError as exc:
                        logger.error(f"SSE stream error: {exc}")
                        yield f"data: {json.dumps({'error': {'message': str(exc)}})}\n\n"
                    except Exception as exc:
                        logger.error(f"SSE stream unexpected error: {exc}")
                        yield f"data: {json.dumps({'error': {'message': str(exc)}})}\n\n"

            return StreamingResponse(
                generate_sse(),
                media_type="text/event-stream",
                headers={
                    "Cache-Control": "no-cache",
                    "Connection": "keep-alive",
                    "X-Accel-Buffering": "no"
                }
            )
        else:
            # 非流式请求
            response = await forward_request(
                target_url,
                "POST",
                headers,
                json_data=body
            )

            if response.status_code != 200:
                logger.error(f"LLM API error: {response.status_code}, {response.text}")
                raise HTTPException(
                    status_code=response.status_code,
                    detail=response.text
                )

            return response.json()

    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail="Invalid JSON in request body") from exc
    except HTTPException:
        raise
    except Exception as exc:
        logger.error(f"Proxy error: {exc}")
        raise HTTPException(status_code=500, detail=str(exc)) from exc

@router.api_route("/{path:path}", methods=["GET", "POST", "PUT", "DELETE", "PATCH"])
async def proxy_other_endpoints(
    request: Request,
    path: str,
    authorization: Optional[str] = Header(None, alias="Authorization")
):
    """代理其他 LLM API 端点，根据 model 从 Redis 获取服务地址"""
    try:
        # 获取请求体（如果是 POST/PUT/PATCH）
        body = None
        model = None
        if request.method in ["POST", "PUT", "PATCH"]:
            try:
                body = await request.json()
                if isinstance(body, dict):
                    model = body.get("model")
            except json.JSONDecodeError:
                body = await request.body()

        # 从 Redis 获取 model 对应的服务地址
        redis_client = request.app.state.redis
        service_base_url = None

        if model:
            service_base_url = await get_model_service_url(redis_client, model)

        # 如果找到了服务地址，使用它；否则使用默认地址
        if service_base_url:
            # 确保 URL 格式正确（移除末尾的斜杠）
            service_base_url = service_base_url.rstrip("/")
            target_url = f"{service_base_url}/{path}"
            logger.info(f"Routing model '{model}' to service: {target_url}")
        else:
            # 使用默认服务地址
            target_url = f"{settings.LLM_API_BASE_URL}/{path}"
            if model:
                logger.warning(f"Model '{model}' not found in Redis, using default service: {target_url}")
            else:
                logger.info(f"No model specified, using default service: {target_url}")

        # 构建请求头
        request_headers = {}
        if authorization:
            request_headers["authorization"] = authorization

        headers = build_llm_headers(request_headers)

        logger.info(f"Proxying {request.method} request to {target_url}, model={model}")

        # 检查是否是流式请求
        stream = False
        if isinstance(body, dict):
            stream = body.get("stream", False)

        # 如果是流式请求，使用 SSE
        if stream and request.method == "POST":
            async def generate_sse():
                async with httpx.AsyncClient(timeout=settings.PROXY_TIMEOUT) as client:
                    try:
                        async with client.stream(
                            request.method,
                            target_url,
                            headers=headers,
                            json=body if isinstance(body, dict) else None,
                            content=body if not isinstance(body, dict) else None,
                            follow_redirects=True
                        ) as response:
                            if response.status_code != 200:
                                error_text = await response.aread()
                                logger.error(f"LLM API error: {response.status_code}, {error_text.decode()}")
                                yield f"data: {json.dumps({'error': {'message': error_text.decode(), 'code': response.status_code}})}\n\n"
                                return

                            async for chunk in response.aiter_bytes():
                                if chunk:
                                    yield chunk.decode('utf-8', errors='ignore')
                    except httpx.RequestError as exc:
                        logger.error(f"SSE stream error: {exc}")
                        yield f"data: {json.dumps({'error': {'message': str(exc)}})}\n\n"
                    except Exception as exc:
                        logger.error(f"SSE stream unexpected error: {exc}")
                        yield f"data: {json.dumps({'error': {'message': str(exc)}})}\n\n"

            return StreamingResponse(
                generate_sse(),
                media_type="text/event-stream",
                headers={
                    "Cache-Control": "no-cache",
                    "Connection": "keep-alive",
                    "X-Accel-Buffering": "no"
                }
            )
        else:
            # 非流式请求
            response = await forward_request(
                target_url,
                request.method,
                headers,
                json_data=body if isinstance(body, dict) else None
            )

            # 返回响应
            if response.headers.get("content-type", "").startswith("application/json"):
                return response.json()
            else:
                return response.text

    except HTTPException:
        raise
    except Exception as exc:
        logger.error(f"Proxy error: {exc}")
        raise HTTPException(status_code=500, detail=str(exc)) from exc
